class Proxy:
    def __init__(self, data):
        # BUG: self.data = data triggers __setattr__ which ok
        # but __getattr__ accessing self.data recurses
        self.data = data

    def __getattr__(self, name):
        # self.data isn't set yet when Python invokes __getattr__
        # during __init__ if anything indirectly queries the attr,
        # infinite recursion
        return self.data[name]


class LazyProxy(Proxy):
    def __init__(self, loader):
        super().__init__({})
        self.loader = loader


def main():
    # Deleting 'data' then reading triggers infinite recursion
    p = Proxy({'name': 'alice'})
    del p.__dict__['data']
    print(p.name)


if __name__ == '__main__':
    main()
